const { readdirSync, readFileSync } = require('fs');
const path = require('path');
const cfg = $('Konfiguration').first().json;
const vaultPfad = cfg.vaultPfad;
const indexOrdner = cfg.indexOrdner || [];
const ausgeschlossen = new Set(cfg.ausgeschlosseneOrdner || []);
const minLen = typeof cfg.minBegrifflaenge === 'number' ? cfg.minBegrifflaenge : 5;

// Einfacher Frontmatter-Parser (key: "value" Zeilen)
function parseFM(content) {
  const fm = {};
  if (!content.startsWith('---')) return fm;
  const end = content.indexOf('---', 3);
  if (end === -1) return fm;
  const block = content.slice(3, end);
  for (const line of block.split('\n')) {
    const m = line.match(/^(\w+):\s*"?(.+?)"?\s*$/);
    if (m) fm[m[1]] = m[2].trim();
  }
  return fm;
}

// Index: suchBegriff (lowercase) → { linkZiel, originalBegriff }
const indexMap = {};

function addTerm(begriff, linkZiel) {
  if (!begriff) return;
  const key = begriff.toLowerCase().trim();
  if (key.length < minLen) return;
  if (!indexMap[key]) {
    indexMap[key] = { linkZiel, originalBegriff: begriff.trim() };
  }
}

function scanDir(dirPath) {
  let entries;
  try { entries = readdirSync(dirPath, { withFileTypes: true }); }
  catch(e) { return; }
  for (const entry of entries) {
    if (entry.isDirectory()) {
      if (!ausgeschlossen.has(entry.name) && !entry.name.startsWith('.')) {
        scanDir(path.join(dirPath, entry.name));
      }
      continue;
    }
    if (!entry.name.endsWith('.md')) continue;
    const linkZiel = entry.name.slice(0, -3);
    // 1. Dateiname selbst als Suchbegriff
    addTerm(linkZiel, linkZiel);
    // 2. Frontmatter-Felder: organisation und name
    try {
      const content = readFileSync(path.join(dirPath, entry.name), 'utf8');
      const fm = parseFM(content);
      if (fm.organisation) addTerm(fm.organisation, linkZiel);
      // name-Feld: Backslash entfernen (Format: "Nachname\ Vorname")
      if (fm.name) addTerm(fm.name.split('\\').join(' ').replace(/  +/g, ' '), linkZiel);
    } catch(e) {}
  }
}

for (const ordner of indexOrdner) {
  scanDir(path.join(vaultPfad, ordner));
}

// Nach Länge absteigend sortieren (längere Begriffe zuerst → verhindert Teilmatches)
const indexArr = Object.entries(indexMap)
  .map(([key, val]) => ({ term: key, linkZiel: val.linkZiel, originalBegriff: val.originalBegriff }))
  .sort((a, b) => b.term.length - a.term.length);

return [{ json: { index: indexArr, anzahl: indexArr.length } }];

const { readdirSync, readFileSync, writeFileSync } = require('fs');
const path = require('path');
const cfg = $('Konfiguration').first().json;
const { index } = $input.first().json;
const vaultPfad = cfg.vaultPfad;
const scanOrdner = cfg.scanOrdner || [];
const ausgeschlossen = new Set(cfg.ausgeschlosseneOrdner || []);
const dryRun = cfg.dryRun !== false;
const nurErstErwaehnung = cfg.nurErstErwaehnung !== false;
const aenderungen = [];

// Frontmatter vom Body trennen
function getBody(content) {
  if (!content.startsWith('---')) return { frontmatter: '', body: content };
  const end = content.indexOf('---', 3);
  if (end === -1) return { frontmatter: '', body: content };
  return { frontmatter: content.slice(0, end + 3), body: content.slice(end + 3) };
}

function verlinken(body, indexArr) {
  const sch = []; // Schutz-Array für geschützte Segmente
  // Schritt 1: Schütze Code-Blöcke, Inline-Code und bestehende Links
  let g = body
    .replace(/```[\s\S]*?```/g, m => { sch.push(m); return '\x00' + (sch.length - 1) + '\x00'; })
    .replace(/`[^`\n]+`/g, m => { sch.push(m); return '\x00' + (sch.length - 1) + '\x00'; })
    .replace(/\[\[[\s\S]*?\]\]/g, m => { sch.push(m); return '\x00' + (sch.length - 1) + '\x00'; })
    .replace(/\[.*?\]\(.*?\)/g, m => { sch.push(m); return '\x00' + (sch.length - 1) + '\x00'; });

  const hinzugefuegt = [];

  // Schritt 2: Suchbegriffe im Body finden und verlinken
  for (const { term, linkZiel, originalBegriff } of indexArr) {
    // Schnellcheck: Suchbegriff überhaupt im Text?
    if (!g.toLowerCase().includes(term)) continue;
    // Sonderzeichen im Suchbegriff escapen
    const escaped = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    // Wortgrenzen: kein Buchstabe/Zahl direkt vor/nach dem Treffer
    const flags = nurErstErwaehnung ? 'i' : 'gi';
    const regex = new RegExp('(?<!\\w)' + escaped + '(?!\\w)', flags);
    let matched = false;
    const neu = g.replace(regex, match => {
      if (nurErstErwaehnung && matched) return match;
      matched = true;
      // Anzeige-Text == Link-Ziel → [[Begriff]], sonst [[Ziel|Begriff]]
      return match === linkZiel ? '[[' + match + ']]' : '[[' + linkZiel + '|' + match + ']]';
    });
    if (matched) {
      // Neu eingefügte [[Links]] sofort schützen
      g = neu.replace(/\[\[[\s\S]*?\]\]/g, m => { sch.push(m); return '\x00' + (sch.length - 1) + '\x00'; });
      hinzugefuegt.push({ term: originalBegriff || term, linkZiel });
    }
  }

  // Schritt 3: Schutz-Platzhalter wiederherstellen
  const neuerBody = g.replace(/\x00(\d+)\x00/g, (_, i) => sch[parseInt(i, 10)]);
  return { neuerBody, hinzugefuegt };
}

function scanDir(dirPath) {
  let entries;
  try { entries = readdirSync(dirPath, { withFileTypes: true }); }
  catch(e) { return; }
  for (const entry of entries) {
    if (entry.isDirectory()) {
      if (!ausgeschlossen.has(entry.name) && !entry.name.startsWith('.')) {
        scanDir(path.join(dirPath, entry.name));
      }
      continue;
    }
    if (!entry.name.endsWith('.md')) continue;
    const filePath = path.join(dirPath, entry.name);
    try {
      const content = readFileSync(filePath, 'utf8');
      const { frontmatter, body } = getBody(content);
      const { neuerBody, hinzugefuegt } = verlinken(body, index);
      if (hinzugefuegt.length > 0) {
        const relPath = filePath.slice(vaultPfad.length + 1);
        aenderungen.push({ datei: relPath, hinzugefuegt });
        if (!dryRun) writeFileSync(filePath, frontmatter + neuerBody, 'utf8');
      }
    } catch(e) {}
  }
}

for (const ordner of scanOrdner) {
  scanDir(path.join(vaultPfad, ordner));
}

const gesamtLinks = aenderungen.reduce((sum, a) => sum + a.hinzugefuegt.length, 0);
return [{ json: { aenderungen, gesamtLinks, geaenderteDateien: aenderungen.length, dryRun } }];

const { writeFileSync, mkdirSync } = require('fs');
const path = require('path');
const cfg = $('Konfiguration').first().json;
const { aenderungen, gesamtLinks, geaenderteDateien, dryRun } = $input.first().json;
const berichtPfad = cfg.berichtPfad;
const today = new Date().toISOString().slice(0, 10);
const nowStr = new Date().toISOString().slice(0, 16).replace('T', ' ');
const modus = dryRun ? 'Dry-Run (keine Änderungen geschrieben)' : 'Live (Dateien wurden geändert)';

let md = '---\n';
md += 'title: "Link-Erkennung ' + nowStr + '"\n';
md += 'datum: ' + today + '\n';
md += 'erstellt: ' + today + '\n';
md += 'typ: Analysen\n';
md += 'status: Archiviert\n';
md += 'tags:\n  - Analyse\n  - Links\n';
md += '---\n\n';
md += '# Link-Erkennung – ' + nowStr + '\n\n';
md += '**Modus:** ' + modus + '  \n';
md += '**Dateien mit Treffern:** ' + geaenderteDateien + '  \n';
md += '**Links gesamt:** ' + gesamtLinks + '  \n\n';
md += '---\n\n';

if (aenderungen.length === 0) {
  md += '_Keine Link-Kandidaten erkannt._\n';
} else {
  for (const { datei, hinzugefuegt } of aenderungen) {
    md += '## ' + datei + '\n\n';
    md += '| Begriff im Text | Link-Ziel |\n|-----------------|----------|\n';
    for (const { term, linkZiel } of hinzugefuegt) {
      md += '| `' + term + '` | [[' + linkZiel + ']] |\n';
    }
    md += '\n';
  }
}

md += '---\n\n';
md += '*Erstellt von Link-Detektor V1 am ' + nowStr + '*\n';

mkdirSync(path.dirname(berichtPfad), { recursive: true });
writeFileSync(berichtPfad, md, 'utf8');

return [{ json: { ok: true, berichtPfad, gesamtLinks, geaenderteDateien, dryRun } }];
